<?php $heading='Permissions';$description='Define individual abilities that can be assigned to roles.';$createPermission='permissions.create';$createUrl='admin/permissions/create';$singular='permission';require BASE_PATH.'/app/Views/partials/admin-header.php'; ?>
<?php $baseUrl='admin/permissions';require BASE_PATH.'/app/Views/partials/table-filters.php'; ?>
<div class="table-card"><table><thead><tr><th>Permission</th><th>Assigned roles</th><th>Created</th><th class="actions-cell">Actions</th></tr></thead><tbody><?php foreach($result['items'] as $item): ?><tr><td><strong><?= htmlspecialchars($item['name'],ENT_QUOTES,'UTF-8') ?></strong><small><?= htmlspecialchars($item['slug'],ENT_QUOTES,'UTF-8') ?></small></td><td><?= (int)$item['role_count'] ?></td><td><?= htmlspecialchars(date('M j, Y',strtotime($item['created_at'])),ENT_QUOTES,'UTF-8') ?></td><td class="actions-cell"><?php if(\App\Core\Auth::can('permissions.update')): ?><a href="<?= htmlspecialchars(url('admin/permissions/'.$item['id'].'/edit'),ENT_QUOTES,'UTF-8') ?>">Edit</a><?php endif; ?><?php if(\App\Core\Auth::can('permissions.delete')): ?><form method="post" action="<?= htmlspecialchars(url('admin/permissions/'.$item['id'].'/delete'),ENT_QUOTES,'UTF-8') ?>" onsubmit="return confirm('Delete this permission?')"><?= csrf_field() ?><button class="danger-link" type="submit">Delete</button></form><?php endif; ?></td></tr><?php endforeach; ?><?php if(!$result['items']): ?><tr><td colspan="4" class="empty-table">No permissions found.</td></tr><?php endif; ?></tbody></table></div><?php require BASE_PATH.'/app/Views/partials/pagination.php'; ?>
